def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Correct initialization
    while left <= right:             # Correct loop condition
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1           # Move left boundary past mid
        else:
            right = mid - 1          # Move right boundary before mid
    return -1

def get_nested_value(data, keys):
    """
    Retrieves a nested value from a dictionary or list using a sequence of keys.

    Returns None if any key is missing or if the structure is invalid at any point.
    """
    result = data
    for key in keys:
        try:
            result = result[key]
        except (KeyError, TypeError, IndexError):
            # KeyError: Key does not exist in a dictionary
            # TypeError: Tried to index a non-subscriptable object (e.g., None, integer)
